import torch
import torch.nn as nn

class ResBlock(nn.Module):
    def __init__(self, dim, dropout=0.05):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(dim, dim),
            nn.LayerNorm(dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim, dim),
            nn.LayerNorm(dim),
        )
        self.act = nn.GELU()
        self.dropout = nn.Dropout(dropout)

    def forward(self, x):
        return self.act(x + self.dropout(self.net(x)))

class ClimSimMLP(nn.Module):
    def __init__(self, input_dim=124, output_dim=128, hidden_dims=[1024, 1024, 1024, 1024], dropout=0.05):
        super().__init__()
        # Input projection
        self.input_proj = nn.Sequential(
            nn.Linear(input_dim, hidden_dims[0]),
            nn.LayerNorm(hidden_dims[0]),
            nn.GELU(),
            nn.Dropout(dropout),
        )

        # Residual blocks
        self.blocks = nn.ModuleList()
        for i in range(len(hidden_dims)):
            self.blocks.append(ResBlock(hidden_dims[0], dropout))

        # Output head
        self.output_head = nn.Linear(hidden_dims[0], output_dim)

    def forward(self, x):
        x = self.input_proj(x)
        for block in self.blocks:
            x = block(x)
        return self.output_head(x)
